class UserRole(Enum):
    LEARNER = "learner"
    EXPERT = "expert"
    ADMIN = "admin"


@dataclass
class CulturalBackground:
    country: str
    languages: list = field(default_factory=list)
    traditions: list = field(default_factory=list)
    interests: list = field(default_factory=list)
    description: str = ""


@dataclass
class UserProfile:
    user_id: str
    username: str
    email: str
    password_hash: str
    role: UserRole = UserRole.LEARNER
    profile_picture: Optional[str] = None
    cultural_background: Optional[CulturalBackground] = None
    created_at: str = ""
    updated_at: str = ""
    is_active: bool = True

    def __post_init__(self):
        if not self.created_at:
            self.created_at = _utcnow().isoformat()
        if not self.updated_at:
            self.updated_at = self.created_at


class UserRegistrationSystem:
    """Handles user registration, authentication, and profile management."""

    def __init__(self):
        self.users: dict[str, UserProfile] = {}
        self.sessions: dict[str, str] = {}  # session_token -> user_id
        self._initialized = True

    @staticmethod
    def _hash_password(password: str, salt: str = "") -> str:
        if not salt:
            salt = os.urandom(16).hex()
        hashed = hashlib.sha256(f"{salt}{password}".encode()).hexdigest()
        return f"{salt}:{hashed}"

    @staticmethod
    def _verify_password(password: str, password_hash: str) -> bool:
        salt, stored_hash = password_hash.split(":")
        computed = hashlib.sha256(f"{salt}{password}".encode()).hexdigest()
        return computed == stored_hash

    def register_user(self, username: str, email: str, password: str,
                      role: UserRole = UserRole.LEARNER) -> dict:
        """Register a new user account."""
        if not username or not email or not password:
            return {"success": False, "error": "All fields are required"}

        if any(u.email == email for u in self.users.values()):
            return {"success": False, "error": "Email already registered"}

        if any(u.username == username for u in self.users.values()):
            return {"success": False, "error": "Username already taken"}

        if len(password) < 8:
            return {"success": False, "error": "Password must be at least 8 characters"}

        user_id = str(uuid.uuid4())
        password_hash = self._hash_password(password)

        user = UserProfile(
            user_id=user_id,
            username=username,
            email=email,
            password_hash=password_hash,
            role=role
        )
        self.users[user_id] = user
        return {"success": True, "user_id": user_id, "username": username}

    def login(self, email: str, password: str) -> dict:
        """Authenticate a user and create a session."""
        user = next((u for u in self.users.values() if u.email == email), None)
        if not user:
            return {"success": False, "error": "Invalid credentials"}

        if not user.is_active:
            return {"success": False, "error": "Account is deactivated"}

        if not self._verify_password(password, user.password_hash):
            return {"success": False, "error": "Invalid credentials"}

        session_token = str(uuid.uuid4())
        self.sessions[session_token] = user.user_id
        return {"success": True, "session_token": session_token, "user_id": user.user_id}

    def logout(self, session_token: str) -> dict:
        """End a user session."""
        if session_token in self.sessions:
            del self.sessions[session_token]
            return {"success": True}
        return {"success": False, "error": "Invalid session"}

    def get_current_user(self, session_token: str) -> Optional[UserProfile]:
        """Get the user associated with a session token."""
        user_id = self.sessions.get(session_token)
        if user_id:
            return self.users.get(user_id)
        return None

    def update_profile(self, user_id: str, **kwargs) -> dict:
        """Update user profile information."""
        user = self.users.get(user_id)
        if not user:
            return {"success": False, "error": "User not found"}

        allowed_fields = {"username", "profile_picture", "cultural_background", "is_active"}
        for key, value in kwargs.items():
            if key in allowed_fields:
                setattr(user, key, value)

        user.updated_at = _utcnow().isoformat()
        return {"success": True, "user_id": user_id}

    def upload_profile_picture(self, user_id: str, image_path: str) -> dict:
        """Upload a profile picture for the user."""
        user = self.users.get(user_id)
        if not user:
            return {"success": False, "error": "User not found"}

        if not image_path:
            return {"success": False, "error": "Image path is required"}

        valid_extensions = (".jpg", ".jpeg", ".png", ".gif", ".webp")
        if not any(image_path.lower().endswith(ext) for ext in valid_extensions):
            return {"success": False, "error": "Invalid image format"}

        user.profile_picture = image_path
        user.updated_at = _utcnow().isoformat()
        return {"success": True, "profile_picture": image_path}

    def set_cultural_background(self, user_id: str, country: str,
                                languages: list = None, traditions: list = None,
                                interests: list = None, description: str = "") -> dict:
        """Set the cultural background for a user."""
        user = self.users.get(user_id)
        if not user:
            return {"success": False, "error": "User not found"}

        background = CulturalBackground(
            country=country,
            languages=languages or [],
            traditions=traditions or [],
            interests=interests or [],
            description=description
        )
        user.cultural_background = background
        user.updated_at = _utcnow().isoformat()
        return {"success": True, "cultural_background": vars(background)}

    def get_user_profile(self, user_id: str) -> Optional[dict]:
        """Retrieve a user's public profile."""
        user = self.users.get(user_id)
        if not user:
            return None
        return {
            "user_id": user.user_id,
            "username": user.username,
            "role": user.role.value,
            "profile_picture": user.profile_picture,
            "cultural_background": vars(user.cultural_background) if user.cultural_background else None,
            "created_at": user.created_at
        }

    def search_users(self, country: str = None, language: str = None,
                     interest: str = None) -> list:
        """Search users by cultural attributes."""
        results = []
        for user in self.users.values():
            if not user.is_active or not user.cultural_background:
                continue
            bg = user.cultural_background
            if country and bg.country.lower() != country.lower():
                continue
            if language and language.lower() not in [l.lower() for l in bg.languages]:
                continue
            if interest and interest.lower() not in [i.lower() for i in bg.interests]:
                continue
            results.append(self.get_user_profile(user.user_id))
        return results


