class VirtualTourModule:
    """Allows users to explore 3D models of cultural landmarks and historical sites."""

    def __init__(self, user_system: UserRegistrationSystem):
        self.user_system = user_system
        self.tours: dict[str, VirtualTour] = {}
        self._initialized = True

    def create_tour(self, creator_id: str, title: str, description: str,
                    model_url: str, country: str = "", category: str = "",
                    thumbnail_url: str = "", tags: list = None) -> dict:
        """Create a new virtual tour."""
        user = self.user_system.users.get(creator_id)
        if not user:
            return {"success": False, "error": "User not found"}

        if not title or not model_url:
            return {"success": False, "error": "Title and model URL are required"}

        tour_id = str(uuid.uuid4())
        tour = VirtualTour(
            tour_id=tour_id,
            title=title,
            description=description,
            creator_id=creator_id,
            model_url=model_url,
            country=country,
            category=category,
            thumbnail_url=thumbnail_url,
            tags=tags or []
        )
        self.tours[tour_id] = tour
        return {"success": True, "tour_id": tour_id}

    def add_hotspot(self, tour_id: str, name: str, description: str,
                    position: dict, hotspot_type: str = "info",
                    media_url: str = None) -> dict:
        """Add an interactive hotspot to a tour."""
        tour = self.tours.get(tour_id)
        if not tour:
            return {"success": False, "error": "Tour not found"}

        required_coords = {"x", "y", "z"}
        if not all(k in position for k in required_coords):
            return {"success": False, "error": "Position must include x, y, z coordinates"}

        valid_types = ("info", "audio", "video", "link")
        if hotspot_type not in valid_types:
            return {"success": False, "error": f"Invalid hotspot type. Must be one of: {valid_types}"}

        hotspot_id = str(uuid.uuid4())
        hotspot = Hotspot(
            hotspot_id=hotspot_id,
            name=name,
            description=description,
            position=position,
            media_url=media_url,
            hotspot_type=hotspot_type
        )
        tour.hotspots.append(hotspot)
        return {"success": True, "hotspot_id": hotspot_id}

    def add_audio_guide(self, tour_id: str, title: str, audio_url: str,
                        transcript: str, language: str = "en",
                        duration_seconds: int = 0) -> dict:
        """Add an audio guide to a tour."""
        tour = self.tours.get(tour_id)
        if not tour:
            return {"success": False, "error": "Tour not found"}

        if not audio_url or not title:
            return {"success": False, "error": "Title and audio URL are required"}

        guide_id = str(uuid.uuid4())
        guide = AudioGuide(
            guide_id=guide_id,
            title=title,
            audio_url=audio_url,
            transcript=transcript,
            language=language,
            duration_seconds=duration_seconds
        )
        tour.audio_guides.append(guide)
        return {"success": True, "guide_id": guide_id}

    def publish_tour(self, tour_id: str, creator_id: str) -> dict:
        """Publish a tour to make it publicly accessible."""
        tour = self.tours.get(tour_id)
        if not tour:
            return {"success": False, "error": "Tour not found"}
        if tour.creator_id != creator_id:
            return {"success": False, "error": "Only the creator can publish this tour"}
        if not tour.hotspots:
            return {"success": False, "error": "Tour must have at least one hotspot"}

        tour.is_published = True
        return {"success": True, "tour_id": tour_id}

    def view_tour(self, tour_id: str, viewer_id: str = None) -> Optional[dict]:
        """View a virtual tour and increment view count."""
        tour = self.tours.get(tour_id)
        if not tour:
            return None
        if not tour.is_published:
            if not viewer_id or tour.creator_id != viewer_id:
                return None

        tour.view_count += 1
        return {
            "tour_id": tour.tour_id,
            "title": tour.title,
            "description": tour.description,
            "model_url": tour.model_url,
            "country": tour.country,
            "category": tour.category,
            "thumbnail_url": tour.thumbnail_url,
            "hotspots": [vars(h) for h in tour.hotspots],
            "audio_guides": [vars(g) for g in tour.audio_guides],
            "view_count": tour.view_count,
            "tags": tour.tags,
            "creator_id": tour.creator_id
        }

    def search_tours(self, country: str = None, category: str = None,
                     keyword: str = None, tag: str = None) -> list:
        """Search published tours by various criteria."""
        results = []
        for tour in self.tours.values():
            if not tour.is_published:
                continue
            if country and tour.country.lower() != country.lower():
                continue
            if category and tour.category.lower() != category.lower():
                continue
            if keyword:
                kw = keyword.lower()
                if kw not in tour.title.lower() and kw not in tour.description.lower():
                    continue
            if tag and tag.lower() not in [t.lower() for t in tour.tags]:
                continue
            results.append({
                "tour_id": tour.tour_id,
                "title": tour.title,
                "country": tour.country,
                "category": tour.category,
                "thumbnail_url": tour.thumbnail_url,
                "view_count": tour.view_count,
                "tags": tour.tags
            })
        return results

    def get_hotspot_details(self, tour_id: str, hotspot_id: str) -> Optional[dict]:
        """Get detailed information about a specific hotspot."""
        tour = self.tours.get(tour_id)
        if not tour:
            return None
        for hotspot in tour.hotspots:
            if hotspot.hotspot_id == hotspot_id:
                return vars(hotspot)
        return None


