    created_at: str = ""

    def __post_init__(self):
        if not self.created_at:
            self.created_at = _utcnow().isoformat()


class TranslationTool:
    """Simple translation utility for language exchange sessions."""

    TRANSLATIONS = {
        ("en", "es"): {"hello": "hola", "goodbye": "adiós", "thank you": "gracias",
                       "how are you": "cómo estás", "please": "por favor",
                       "good morning": "buenos días", "good night": "buenas noches"},
        ("en", "fr"): {"hello": "bonjour", "goodbye": "au revoir", "thank you": "merci",
                       "how are you": "comment allez-vous", "please": "s'il vous plaît",
                       "good morning": "bonjour", "good night": "bonne nuit"},
        ("en", "de"): {"hello": "hallo", "goodbye": "auf wiedersehen", "thank you": "danke",
                       "how are you": "wie geht es ihnen", "please": "bitte",
                       "good morning": "guten morgen", "good night": "gute nacht"},
        ("en", "ja"): {"hello": "こんにちは", "goodbye": "さようなら", "thank you": "ありがとう",
                       "how are you": "お元気ですか", "please": "お願いします",
                       "good morning": "おはようございます", "good night": "おやすみなさい"},
        ("en", "zh"): {"hello": "你好", "goodbye": "再见", "thank you": "谢谢",
                       "how are you": "你好吗", "please": "请",
                       "good morning": "早上好", "good night": "晚安"},
    }

    def translate(self, text: str, source_lang: str, target_lang: str) -> dict:
        """Translate text between languages."""
        if not text:
            return {"success": False, "error": "Text is required"}

        key = (source_lang.lower(), target_lang.lower())
        reverse_key = (target_lang.lower(), source_lang.lower())

        translation_dict = self.TRANSLATIONS.get(key)
        if not translation_dict:
            reverse_dict = self.TRANSLATIONS.get(reverse_key)
            if reverse_dict:
                translation_dict = {v: k for k, v in reverse_dict.items()}

        if translation_dict:
            translated = translation_dict.get(text.lower())
            if translated:
                return {
                    "success": True,
                    "original": text,
                    "translated": translated,
                    "source_language": source_lang,
                    "target_language": target_lang
                }

        return {
            "success": True,
            "original": text,
            "translated": f"[{target_lang}] {text}",
            "source_language": source_lang,
            "target_language": target_lang,
            "note": "Machine translation approximation"
        }

    def get_supported_languages(self) -> list:
        """Get list of supported language pairs."""
        languages = set()
        for src, tgt in self.TRANSLATIONS.keys():
            languages.add(src)
            languages.add(tgt)
        return sorted(languages)


class LanguageLearningModule:
    """Pairs users for real-time language exchanges with translation assistance."""

    def __init__(self, user_system: UserRegistrationSystem,
                 tour_module: VirtualTourModule):
        self.user_system = user_system
        self.tour_module = tour_module
        self.pairing_requests: dict[str, LanguagePairingRequest] = {}
        self.sessions: dict[str, LanguageExchangeSession] = {}
        self.translation_tool = TranslationTool()
        self._initialized = True

    def request_pairing(self, user_id: str, native_language: str,
                        target_language: str, proficiency_level: str = "beginner") -> dict:
        """Submit a pairing request for language exchange."""
        user = self.user_system.users.get(user_id)
        if not user:
            return {"success": False, "error": "User not found"}

        valid_levels = ("beginner", "intermediate", "advanced")
        if proficiency_level not in valid_levels:
            return {"success": False, "error": f"Proficiency must be one of: {valid_levels}"}

        # Check for existing active request
        for req in self.pairing_requests.values():
            if req.user_id == user_id and req.status == PairingStatus.WAITING:
                return {"success": False, "error": "You already have an active pairing request"}

        request_id = str(uuid.uuid4())
        request = LanguagePairingRequest(
            request_id=request_id,
            user_id=user_id,
            native_language=native_language.lower(),
            target_language=target_language.lower(),
            proficiency_level=proficiency_level
        )
        self.pairing_requests[request_id] = request

        # Attempt auto-match
        match = self._find_match(request)
        if match:
            session = self._create_session(request, match)
            return {
                "success": True,
                "request_id": request_id,
                "matched": True,
                "session_id": session.session_id,
                "partner_id": match.user_id
            }

        return {"success": True, "request_id": request_id, "matched": False}

    def _find_match(self, request: LanguagePairingRequest) -> Optional[LanguagePairingRequest]:
        """Find a compatible pairing partner."""
        for req in self.pairing_requests.values():
            if req.request_id == request.request_id:
                continue
            if req.status != PairingStatus.WAITING:
                continue
            if req.user_id == request.user_id:
                continue
            # Match: one person's native is the other's target
            if (req.native_language == request.target_language and
                    req.target_language == request.native_language):
                return req
        return None

    def _create_session(self, req1: LanguagePairingRequest,
                        req2: LanguagePairingRequest) -> LanguageExchangeSession:
        """Create a language exchange session between two matched users."""
        session_id = str(uuid.uuid4())
        session = LanguageExchangeSession(
            session_id=session_id,
            user1_id=req1.user_id,
            user2_id=req2.user_id,
            language_practiced=f"{req1.native_language}/{req2.native_language}",
            status=PairingStatus.IN_SESSION
        )
        self.sessions[session_id] = session
        req1.status = PairingStatus.PAIRED
        req2.status = PairingStatus.PAIRED
        return session

    def send_message(self, session_id: str, sender_id: str, text: str,
                     auto_translate: bool = False) -> dict:
        """Send a message in a language exchange session."""
        session = self.sessions.get(session_id)
        if not session:
            return {"success": False, "error": "Session not found"}

        if session.status != PairingStatus.IN_SESSION:
            return {"success": False, "error": "Session is not active"}

        if sender_id not in (session.user1_id, session.user2_id):
            return {"success": False, "error": "User not part of this session"}

        message = {
            "sender_id": sender_id,
            "text": text,
            "timestamp": _utcnow().isoformat()
        }

        if auto_translate:
            langs = session.language_practiced.split("/")
            # Determine target language based on sender
            if sender_id == session.user1_id:
                source_lang, target_lang = langs[0], langs[1]
            else:
                source_lang, target_lang = langs[1], langs[0]

            translation = self.translation_tool.translate(text, source_lang, target_lang)
            if translation["success"]:
                message["translation"] = translation["translated"]
                session.translations.append(TranslationRequest(
                    request_id=str(uuid.uuid4()),
                    source_text=text,
                    source_language=source_lang,
                    target_language=target_lang,
                    translated_text=translation["translated"]
                ))

        session.messages.append(message)
        return {"success": True, "message": message}

    def translate_text(self, text: str, source_lang: str, target_lang: str) -> dict:
        """Translate text using the built-in translation tool."""
        return self.translation_tool.translate(text, source_lang, target_lang)

    def end_session(self, session_id: str, user_id: str) -> dict:
        """End a language exchange session."""
        session = self.sessions.get(session_id)
        if not session:
            return {"success": False, "error": "Session not found"}

        if user_id not in (session.user1_id, session.user2_id):
            return {"success": False, "error": "User not part of this session"}

        session.status = PairingStatus.COMPLETED
        session.ended_at = _utcnow().isoformat()
        if session.started_at:
            start = datetime.fromisoformat(session.started_at)
            end = datetime.fromisoformat(session.ended_at)
            session.duration_minutes = int((end - start).total_seconds() / 60)

        return {
            "success": True,
            "session_id": session_id,
            "duration_minutes": session.duration_minutes,
            "messages_exchanged": len(session.messages)
        }

    def cancel_pairing_request(self, request_id: str, user_id: str) -> dict:
        """Cancel an active pairing request."""
        request = self.pairing_requests.get(request_id)
        if not request:
            return {"success": False, "error": "Request not found"}
        if request.user_id != user_id:
            return {"success": False, "error": "Not authorized"}
        if request.status != PairingStatus.WAITING:
            return {"success": False, "error": "Request is no longer active"}

        request.status = PairingStatus.CANCELLED
        return {"success": True}

    def get_session_history(self, user_id: str) -> list:
        """Get a user's language exchange session history."""
        history = []
        for session in self.sessions.values():
            if user_id in (session.user1_id, session.user2_id):
                partner_id = (session.user2_id if user_id == session.user1_id
                              else session.user1_id)
                history.append({
                    "session_id": session.session_id,
                    "partner_id": partner_id,
                    "language_practiced": session.language_practiced,
                    "status": session.status.value,
                    "duration_minutes": session.duration_minutes,
                    "messages_count": len(session.messages),
                    "started_at": session.started_at
                })
        return history

    def get_supported_languages(self) -> list:
        """Get list of supported languages for translation."""
        return self.translation_tool.get_supported_languages()


