class WorkshopType(Enum):
    LIVE = "live"
    PRE_RECORDED = "pre_recorded"


class WorkshopStatus(Enum):
    SCHEDULED = "scheduled"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"
    CANCELLED = "cancelled"


@dataclass
class WorkshopQuestion:
    question_id: str
    user_id: str
    text: str
    answer: str = ""
    answered_by: str = ""
    timestamp: str = ""
    is_answered: bool = False

    def __post_init__(self):
        if not self.timestamp:
            self.timestamp = _utcnow().isoformat()


@dataclass
class DiscussionPost:
    post_id: str
    user_id: str
    text: str
    replies: list = field(default_factory=list)
    timestamp: str = ""

    def __post_init__(self):
        if not self.timestamp:
            self.timestamp = _utcnow().isoformat()


@dataclass
class CulturalWorkshop:
    workshop_id: str
    title: str
    description: str
    host_id: str
    workshop_type: WorkshopType
    category: str  # "cooking", "music", "dance", "art", "history", "language", "customs"
    country: str
    status: WorkshopStatus = WorkshopStatus.SCHEDULED
    scheduled_at: str = ""
    duration_minutes: int = 60
    max_participants: int = 50
    participants: list = field(default_factory=list)
    questions: list = field(default_factory=list)
    discussions: list = field(default_factory=list)
    recording_url: str = ""
    materials: list = field(default_factory=list)
    tags: list = field(default_factory=list)
    created_at: str = ""

    def __post_init__(self):
        if not self.created_at:
            self.created_at = _utcnow().isoformat()


class CulturalWorkshopModule:
    """Hosts live and pre-recorded cultural sessions led by experts."""

    def __init__(self, user_system: UserRegistrationSystem,
                 language_module: LanguageLearningModule):
        self.user_system = user_system
        self.language_module = language_module
        self.workshops: dict[str, CulturalWorkshop] = {}
        self._initialized = True

    def create_workshop(self, host_id: str, title: str, description: str,
                        workshop_type: str, category: str, country: str,
                        scheduled_at: str = "", duration_minutes: int = 60,
                        max_participants: int = 50, recording_url: str = "",
                        materials: list = None, tags: list = None) -> dict:
        """Create a new cultural workshop."""
        user = self.user_system.users.get(host_id)
        if not user:
            return {"success": False, "error": "User not found"}

        if user.role not in (UserRole.EXPERT, UserRole.ADMIN):
            return {"success": False, "error": "Only experts and admins can create workshops"}

        if not title or not description:
            return {"success": False, "error": "Title and description are required"}

        try:
            w_type = WorkshopType(workshop_type)
        except ValueError:
            return {"success": False, "error": "Invalid workshop type. Use 'live' or 'pre_recorded'"}

        valid_categories = ("cooking", "music", "dance", "art", "history",
                            "language", "customs", "crafts", "storytelling")
        if category not in valid_categories:
            return {"success": False, "error": f"Invalid category. Must be one of: {valid_categories}"}

        workshop_id = str(uuid.uuid4())
        workshop = CulturalWorkshop(
            workshop_id=workshop_id,
            title=title,
            description=description,
            host_id=host_id,
            workshop_type=w_type,
            category=category,
            country=country,
            scheduled_at=scheduled_at or _utcnow().isoformat(),
            duration_minutes=duration_minutes,
            max_participants=max_participants,
            recording_url=recording_url,
            materials=materials or [],
            tags=tags or []
        )
        self.workshops[workshop_id] = workshop
        return {"success": True, "workshop_id": workshop_id}

    def join_workshop(self, workshop_id: str, user_id: str) -> dict:
        """Join a workshop as a participant."""
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}

        user = self.user_system.users.get(user_id)
        if not user:
            return {"success": False, "error": "User not found"}

        if workshop.status == WorkshopStatus.CANCELLED:
            return {"success": False, "error": "Workshop has been cancelled"}

        if user_id in workshop.participants:
            return {"success": False, "error": "Already joined this workshop"}

        if len(workshop.participants) >= workshop.max_participants:
            return {"success": False, "error": "Workshop is full"}

        workshop.participants.append(user_id)
        return {
            "success": True,
            "workshop_id": workshop_id,
            "participant_count": len(workshop.participants)
        }

    def leave_workshop(self, workshop_id: str, user_id: str) -> dict:
        """Leave a workshop."""
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}

        if user_id not in workshop.participants:
            return {"success": False, "error": "Not a participant"}

        workshop.participants.remove(user_id)
        return {"success": True}

    def start_workshop(self, workshop_id: str, host_id: str) -> dict:
        """Start a live workshop session."""
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}

        if workshop.host_id != host_id:
            return {"success": False, "error": "Only the host can start the workshop"}

        if workshop.status != WorkshopStatus.SCHEDULED:
            return {"success": False, "error": "Workshop cannot be started in its current state"}

        workshop.status = WorkshopStatus.IN_PROGRESS
        return {"success": True, "status": "in_progress"}

    def end_workshop(self, workshop_id: str, host_id: str,
                     recording_url: str = "") -> dict:
        """End a live workshop session."""
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}

        if workshop.host_id != host_id:
            return {"success": False, "error": "Only the host can end the workshop"}

        if workshop.status != WorkshopStatus.IN_PROGRESS:
            return {"success": False, "error": "Workshop is not currently in progress"}

        workshop.status = WorkshopStatus.COMPLETED
        if recording_url:
            workshop.recording_url = recording_url
        return {
            "success": True,
            "status": "completed",
            "participant_count": len(workshop.participants)
        }

    def ask_question(self, workshop_id: str, user_id: str, text: str) -> dict:
        """Ask a question during a workshop."""
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}

        if user_id not in workshop.participants and user_id != workshop.host_id:
            return {"success": False, "error": "Must be a participant to ask questions"}

        if not text.strip():
            return {"success": False, "error": "Question text cannot be empty"}

        question_id = str(uuid.uuid4())
        question = WorkshopQuestion(
            question_id=question_id,
            user_id=user_id,
            text=text
        )
        workshop.questions.append(question)
        return {"success": True, "question_id": question_id}

    def answer_question(self, workshop_id: str, question_id: str,
                        answerer_id: str, answer: str) -> dict:
        """Answer a question in a workshop."""
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}

        if answerer_id != workshop.host_id:
            return {"success": False, "error": "Only the host can answer questions"}

        for question in workshop.questions:
            if question.question_id == question_id:
                question.answer = answer
                question.answered_by = answerer_id
                question.is_answered = True
                return {"success": True, "question_id": question_id}

        return {"success": False, "error": "Question not found"}

    def post_discussion(self, workshop_id: str, user_id: str, text: str) -> dict:
        """Post a discussion message in a workshop."""
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}

        if user_id not in workshop.participants and user_id != workshop.host_id:
            return {"success": False, "error": "Must be a participant to post discussions"}

        if not text.strip():
            return {"success": False, "error": "Discussion text cannot be empty"}

        post_id = str(uuid.uuid4())
        post = DiscussionPost(post_id=post_id, user_id=user_id, text=text)
        workshop.discussions.append(post)
        return {"success": True, "post_id": post_id}

    def reply_to_discussion(self, workshop_id: str, post_id: str,
                            user_id: str, text: str) -> dict:
        """Reply to a discussion post."""
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return {"success": False, "error": "Workshop not found"}

        if user_id not in workshop.participants and user_id != workshop.host_id:
            return {"success": False, "error": "Must be a participant to reply"}

        for post in workshop.discussions:
            if post.post_id == post_id:
                reply = {
                    "reply_id": str(uuid.uuid4()),
                    "user_id": user_id,
                    "text": text,
                    "timestamp": _utcnow().isoformat()
                }
                post.replies.append(reply)
                return {"success": True, "reply_id": reply["reply_id"]}

        return {"success": False, "error": "Discussion post not found"}

    def search_workshops(self, country: str = None, category: str = None,
                         workshop_type: str = None, keyword: str = None,
                         status: str = None) -> list:
        """Search available workshops."""
        results = []
        for workshop in self.workshops.values():
            if country and workshop.country.lower() != country.lower():
                continue
            if category and workshop.category.lower() != category.lower():
                continue
            if workshop_type:
                try:
                    if workshop.workshop_type != WorkshopType(workshop_type):
                        continue
                except ValueError:
                    continue
            if keyword:
                kw = keyword.lower()
                if kw not in workshop.title.lower() and kw not in workshop.description.lower():
                    continue
            if status:
                try:
                    if workshop.status != WorkshopStatus(status):
                        continue
                except ValueError:
                    continue
            results.append({
                "workshop_id": workshop.workshop_id,
                "title": workshop.title,
                "host_id": workshop.host_id,
                "category": workshop.category,
                "country": workshop.country,
                "type": workshop.workshop_type.value,
                "status": workshop.status.value,
                "scheduled_at": workshop.scheduled_at,
                "participant_count": len(workshop.participants),
                "max_participants": workshop.max_participants,
                "tags": workshop.tags
            })
        return results

    def get_workshop_details(self, workshop_id: str) -> Optional[dict]:
        """Get full details of a workshop."""
        workshop = self.workshops.get(workshop_id)
        if not workshop:
            return None
        return {
            "workshop_id": workshop.workshop_id,
            "title": workshop.title,
            "description": workshop.description,
            "host_id": workshop.host_id,
            "type": workshop.workshop_type.value,
            "category": workshop.category,
            "country": workshop.country,
            "status": workshop.status.value,
            "scheduled_at": workshop.scheduled_at,
            "duration_minutes": workshop.duration_minutes,
            "participant_count": len(workshop.participants),
            "max_participants": workshop.max_participants,
            "questions": [vars(q) for q in workshop.questions],
            "discussions": [{
                "post_id": d.post_id,
                "user_id": d.user_id,
                "text": d.text,
                "replies": d.replies,
                "timestamp": d.timestamp
            } for d in workshop.discussions],
            "recording_url": workshop.recording_url,
            "materials": workshop.materials,
            "tags": workshop.tags
        }


