class CulturalExchangeHub:
    """
    Main platform class that integrates all modules.
    Modules are initialized in dependency order:
    1. User Registration -> 2. Virtual Tours -> 3. Language Learning ->
    4. Cultural Workshops -> 5. Feedback & Ratings
    """

    def __init__(self):
        # Module 1: User Registration (foundation)
        self.user_system = UserRegistrationSystem()

        # Module 2: Virtual Tours (depends on user system)
        self.tour_module = VirtualTourModule(self.user_system)

        # Module 3: Language Learning (depends on tour module)
        self.language_module = LanguageLearningModule(
            self.user_system, self.tour_module
        )

        # Module 4: Cultural Workshops (depends on language module)
        self.workshop_module = CulturalWorkshopModule(
            self.user_system, self.language_module
        )

        # Module 5: Feedback & Ratings (depends on all other modules)
        self.feedback_system = FeedbackRatingSystem(
            self.user_system, self.tour_module,
            self.language_module, self.workshop_module
        )

        self._platform_name = "CulturalExchangeHub"
        self._version = "1.0.0"

    @property
    def platform_info(self) -> dict:
        """Get platform information and module status."""
        return {
            "name": self._platform_name,
            "version": self._version,
            "modules": {
                "user_registration": self.user_system._initialized,
                "virtual_tours": self.tour_module._initialized,
                "language_learning": self.language_module._initialized,
                "cultural_workshops": self.workshop_module._initialized,
                "feedback_ratings": self.feedback_system._initialized,
            },
            "statistics": self.get_platform_statistics()
        }

    def get_platform_statistics(self) -> dict:
        """Get platform-wide statistics."""
        return {
            "total_users": len(self.user_system.users),
            "active_users": sum(1 for u in self.user_system.users.values() if u.is_active),
            "total_tours": len(self.tour_module.tours),
            "published_tours": sum(1 for t in self.tour_module.tours.values() if t.is_published),
            "language_sessions": len(self.language_module.sessions),
            "active_pairing_requests": sum(
                1 for r in self.language_module.pairing_requests.values()
                if r.status == PairingStatus.WAITING
            ),
            "total_workshops": len(self.workshop_module.workshops),
            "total_reviews": len(self.feedback_system.reviews),
        }

    def get_user_dashboard(self, user_id: str) -> Optional[dict]:
        """Get a personalized dashboard for a user."""
        user = self.user_system.users.get(user_id)
        if not user:
            return None

        return {
            "profile": self.user_system.get_user_profile(user_id),
            "language_sessions": self.language_module.get_session_history(user_id),
            "reviews_written": self.feedback_system.get_user_reviews(user_id),
            "workshops_joined": [
                w.workshop_id for w in self.workshop_module.workshops.values()
                if user_id in w.participants
            ],
            "tours_created": [
                t.tour_id for t in self.tour_module.tours.values()
                if t.creator_id == user_id
            ]
        }


