def main():
    """Demonstrate the CulturalExchangeHub platform."""
    hub = CulturalExchangeHub()
    print(f"=== {hub._platform_name} v{hub._version} ===\n")

    # --- Module 1: User Registration ---
    print("--- Module 1: User Registration ---")
    user1 = hub.user_system.register_user("akiko_tanaka", "akiko@example.com", "password123")
    print(f"Registered: {user1}")

    user2 = hub.user_system.register_user("carlos_garcia", "carlos@example.com", "password456")
    print(f"Registered: {user2}")

    expert = hub.user_system.register_user("prof_chen", "chen@example.com", "password789",
                                           role=UserRole.EXPERT)
    print(f"Registered expert: {expert}")

    # Set cultural backgrounds
    hub.user_system.set_cultural_background(
        user1["user_id"], "Japan",
        languages=["Japanese", "English"],
        traditions=["Tea Ceremony", "Ikebana"],
        interests=["Calligraphy", "Anime", "History"]
