    hub.user_system.set_cultural_background(
        user2["user_id"], "Mexico",
        languages=["Spanish", "English"],
        traditions=["Dia de los Muertos", "Quinceañera"],
        interests=["Cooking", "Music", "Dance"]
    )

    hub.user_system.set_cultural_background(
        expert["user_id"], "China",
        languages=["Chinese", "English", "Japanese"],
        traditions=["Dragon Boat Festival", "Chinese New Year"],
        interests=["History", "Art", "Language Teaching"]
    )

    # Upload profile pictures
    hub.user_system.upload_profile_picture(user1["user_id"], "profiles/akiko.jpg")
    hub.user_system.upload_profile_picture(user2["user_id"], "profiles/carlos.png")

    # Login
    login_result = hub.user_system.login("akiko@example.com", "password123")
    print(f"Login: {login_result['success']}")

    # Search users
    japanese_users = hub.user_system.search_users(country="Japan")
    print(f"Users from Japan: {len(japanese_users)}")

    # --- Module 2: Virtual Tours ---
    print("\n--- Module 2: Virtual Tours ---")
    tour_result = hub.tour_module.create_tour(
        creator_id=user1["user_id"],
        title="Kyoto Imperial Palace",
        description="Explore the historic residence of Japan's Imperial family",
        model_url="https://models.example.com/kyoto-palace.glb",
        country="Japan",
        category="landmark",
        tags=["history", "architecture", "japan"]
    )
    print(f"Tour created: {tour_result}")

    # Add hotspots
    hub.tour_module.add_hotspot(
        tour_result["tour_id"],
        name="Main Gate (Kenreimon)",
        description="The ceremonial gate used for important state occasions",
        position={"x": 10.5, "y": 0.0, "z": 15.2},
        hotspot_type="info"
    )

    hub.tour_module.add_hotspot(
        tour_result["tour_id"],
        name="Throne Room",
        description="Where the Emperor received dignitaries",
        position={"x": 25.0, "y": 3.0, "z": 20.0},
        hotspot_type="audio",
        media_url="https://audio.example.com/throne-room-guide.mp3"
    )

    # Add audio guide
    hub.tour_module.add_audio_guide(
        tour_result["tour_id"],
        title="Palace History Overview",
        audio_url="https://audio.example.com/palace-history.mp3",
        transcript="The Kyoto Imperial Palace has been the residence...",
        language="en",
        duration_seconds=300
    )

    # Publish tour
    pub_result = hub.tour_module.publish_tour(tour_result["tour_id"], user1["user_id"])
    print(f"Tour published: {pub_result['success']}")

    # View tour
    tour_view = hub.tour_module.view_tour(tour_result["tour_id"])
    print(f"Tour '{tour_view['title']}' has {len(tour_view['hotspots'])} hotspots")

    # Search tours
    japan_tours = hub.tour_module.search_tours(country="Japan")
    print(f"Tours in Japan: {len(japan_tours)}")

    # --- Module 3: Language Learning ---
    print("\n--- Module 3: Language Learning ---")

    # User 1 (Japanese native) wants to learn Spanish
    pair1 = hub.language_module.request_pairing(
        user1["user_id"], "ja", "es", "beginner"
    )
    print(f"Pairing request 1: matched={pair1.get('matched', False)}")

    # User 2 (Spanish native) wants to learn Japanese - should auto-match
    pair2 = hub.language_module.request_pairing(
        user2["user_id"], "es", "ja", "beginner"
    )
    print(f"Pairing request 2: matched={pair2.get('matched', False)}")

    if pair2.get("matched"):
        session_id = pair2["session_id"]

        # Exchange messages
        hub.language_module.send_message(
            session_id, user1["user_id"], "hello", auto_translate=True
        )
        hub.language_module.send_message(
            session_id, user2["user_id"], "hola", auto_translate=True
        )

        # Use translation tool
        translation = hub.language_module.translate_text("thank you", "en", "es")
        print(f"Translation: 'thank you' -> '{translation['translated']}'")

        # End session
        end_result = hub.language_module.end_session(session_id, user1["user_id"])
        print(f"Session ended: {end_result['messages_exchanged']} messages exchanged")

    # Get supported languages
    languages = hub.language_module.get_supported_languages()
    print(f"Supported languages: {languages}")

    # --- Module 4: Cultural Workshops ---
    print("\n--- Module 4: Cultural Workshops ---")

    workshop_result = hub.workshop_module.create_workshop(
        host_id=expert["user_id"],
        title="Introduction to Chinese Calligraphy",
        description="Learn the basics of Chinese brush calligraphy with Prof. Chen",
        workshop_type="live",
        category="art",
        country="China",
        duration_minutes=90,
        max_participants=30,
        tags=["calligraphy", "art", "chinese", "beginner"]
    )
    print(f"Workshop created: {workshop_result}")

    # Users join
    join1 = hub.workshop_module.join_workshop(workshop_result["workshop_id"], user1["user_id"])
    join2 = hub.workshop_module.join_workshop(workshop_result["workshop_id"], user2["user_id"])
    print(f"Participants joined: {join1['participant_count']}, {join2['participant_count']}")

    # Start workshop
    hub.workshop_module.start_workshop(workshop_result["workshop_id"], expert["user_id"])

    # Ask questions
    q_result = hub.workshop_module.ask_question(
        workshop_result["workshop_id"], user1["user_id"],
        "What brush size is best for beginners?"
    )
    print(f"Question asked: {q_result['success']}")

    # Answer question
    hub.workshop_module.answer_question(
        workshop_result["workshop_id"], q_result["question_id"],
        expert["user_id"],
        "I recommend starting with a medium-sized brush (about 2cm width)."
    )

    # Post discussion
    hub.workshop_module.post_discussion(
        workshop_result["workshop_id"], user2["user_id"],
        "This is fascinating! Does anyone know a good place to buy supplies?"
    )

    # End workshop
    end_ws = hub.workshop_module.end_workshop(
        workshop_result["workshop_id"], expert["user_id"],
        recording_url="https://recordings.example.com/calligraphy-101.mp4"
    )
    print(f"Workshop ended: {end_ws['participant_count']} participants")

    # Search workshops
    art_workshops = hub.workshop_module.search_workshops(category="art")
    print(f"Art workshops: {len(art_workshops)}")

    # --- Module 5: Feedback & Ratings ---
    print("\n--- Module 5: Feedback & Ratings ---")

    # Review the virtual tour
    review1 = hub.feedback_system.submit_review(
        reviewer_id=user2["user_id"],
        target_id=tour_result["tour_id"],
        category="virtual_tour",
        rating=5,
        title="Stunning virtual experience!",
        comment="The 3D model is incredibly detailed. The hotspots provide great historical context."
    )
    print(f"Tour review: {review1}")

    # Review the workshop
    review2 = hub.feedback_system.submit_review(
        reviewer_id=user1["user_id"],
        target_id=workshop_result["workshop_id"],
        category="workshop",
        rating=4,
        title="Great introduction to calligraphy",
        comment="Prof. Chen is an excellent teacher. Would love a follow-up session."
    )
    print(f"Workshop review: {review2}")

    # Review the language exchange session
    if pair2.get("matched"):
        review3 = hub.feedback_system.submit_review(
            reviewer_id=user1["user_id"],
            target_id=pair2["session_id"],
            category="language_exchange",
            rating=4,
            title="Fun language practice!",
            comment="Carlos was very patient. The translation tool was helpful."
        )
        print(f"Exchange review: {review3}")

    # Get ratings summary
    tour_ratings = hub.feedback_system.get_ratings_summary(tour_result["tour_id"])
    print(f"Tour ratings: avg={tour_ratings['average_rating']}, "
          f"count={tour_ratings['total_reviews']}")

    # Mark review as helpful
    hub.feedback_system.mark_helpful(review1["review_id"], user1["user_id"])

    # Get top rated tours
    top_tours = hub.feedback_system.get_top_rated("virtual_tour")
    print(f"Top rated tours: {len(top_tours)}")

    # --- Platform Statistics ---
    print("\n--- Platform Statistics ---")
    stats = hub.get_platform_statistics()
    for key, value in stats.items():
        print(f"  {key}: {value}")

    # User dashboard
    dashboard = hub.get_user_dashboard(user1["user_id"])
    print(f"\nDashboard for {dashboard['profile']['username']}:")
    print(f"  Language sessions: {len(dashboard['language_sessions'])}")
    print(f"  Reviews written: {len(dashboard['reviews_written'])}")
    print(f"  Workshops joined: {len(dashboard['workshops_joined'])}")
    print(f"  Tours created: {len(dashboard['tours_created'])}")

    print(f"\n=== {hub._platform_name} Demo Complete ===")


if __name__ == "__main__":
    main()
